parameters.jsCode:
const claudeResponse = $input.item.json;
const consolidation = claudeResponse.content?.[0]?.text || 'Sem consolidação disponível';
const date = new Date().toISOString().split('T')[0];
const weekStart = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];

const update = [
  `\n---`,
  `## Consolidação Semanal: ${weekStart} → ${date}`,
  '',
  consolidation,
  '',
  `_Gerado automaticamente pelo WF-011 em ${new Date().toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' })}_`
].join('\n');

return [{ json: { update, consolidation, date, weekStart } }];

